<?php/** * Combined Live TV M3U8 Generator * Serves a direct 720p variant by replacing the master playlist link. */// Define the variant here - change this string for 1080p etc.$Output_Variant = 'ARYDigitalHDh264_720p';header('Content-Type: application/vnd.apple.mpegurl');header('Content-Disposition: inline; filename="live-tv.m3u8"');header('Cache-Control: no-cache, must-revalidate');header('Access-Control-Allow-Origin: *');echo "#EXTM3U\n";// Fetch the modified URL$ary_url = getFreshAryUrl($Output_Variant);if ($ary_url) {    echo '#EXTINF:-1 tvg-name="ARY Digital" tvg-id="ARYDigital.pk" tvg-language="Urdu" tvg-country="PK" tvg-logo="https://upload.wikimedia.org/wikipedia/en/4/4b/ARY_Digital.png" group-title="Entertainment",ARY Digital' . "\n";    echo '#EXTVLCOPT:http-user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36' . "\n";    echo '#EXTVLCOPT:http-referrer=https://live.arydigital.tv/' . "\n";    echo '#EXTVLCOPT:http-origin=https://live.arydigital.tv' . "\n";    echo $ary_url . "\n\n";}/** * Scrapes the webpage and performs the string replacement */function getFreshAryUrl($variant) {    $ch = curl_init();    curl_setopt_array($ch, [        CURLOPT_URL => 'https://live.arydigital.tv/',        CURLOPT_RETURNTRANSFER => true,        CURLOPT_FOLLOWLOCATION => true,        CURLOPT_TIMEOUT => 8,        CURLOPT_USERAGENT => 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',        CURLOPT_HTTPHEADER => [            'Accept: text/html,application/xhtml+xml',            'Referer: https://live.arydigital.tv/',        ],    ]);    $html = curl_exec($ch);    $http_code = curl_getinfo($ch, CURLINFO_HTTP_CODE);    curl_close($ch);    if ($http_code == 200) {        // Find the main.m3u8 link in the page source        if (preg_match('/https:\/\/arydigital\.aryzap\.com\/[a-f0-9]+\/[a-f0-9]+\/v1\/[a-f0-9]+\/[a-f0-9]+\/main\.m3u8/', $html, $matches)) {            $master_url = $matches[0];                        // Swap main.m3u8 with the variant defined at the top            return str_replace('main.m3u8', $variant . '.m3u8', $master_url);        }    }    return false;}